function solve(edges, online, k) {
    const n = online.length;
    const graph = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        graph[u].push({ to: v, cost });
    }

    const pq = new PriorityQueue((a, b) => a.totalCost - b.totalCost);
    pq.enqueue({ node: 0, totalCost: 0, minEdge: Infinity });

    let maxScore = -1;

    while (!pq.isEmpty()) {
        const { node, totalCost, minEdge } = pq.dequeue();

        if (node === n - 1) {
            if (totalCost <= k) {
                const currentMin = minEdge === Infinity ? -1 : minEdge;
                maxScore = Math.max(maxScore, currentMin);
            }
            continue;
        }

        for (const { to, cost } of graph[node]) {
            if (!online[to] && to !== n - 1) {
                continue;
            }
            const newTotal = totalCost + cost;
            if (newTotal > k) {
                continue;
            }
            const newMin = Math.min(minEdge, cost);
            pq.enqueue({ node: to, totalCost: newTotal, minEdge: newMin });
        }
    }

    return maxScore;
}

class PriorityQueue {
    constructor(comparator = (a, b) => a - b) {
        this.heap = [];
        this.comparator = comparator;
    }

    enqueue(value) {
        this.heap.push(value);
        this.bubbleUp();
    }

    dequeue() {
        const root = this.heap[0];
        const last = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this.bubbleDown();
        }
        return root;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    bubbleUp() {
        let index = this.heap.length - 1;
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) break;
            [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
            index = parentIndex;
        }
    }

    bubbleDown() {
        let index = 0;
        const length = this.heap.length;
        while (true) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let swapIndex = null;
            if (leftChildIndex < length) {
                if (this.comparator(this.heap[leftChildIndex], this.heap[index]) < 0) {
                    swapIndex = leftChildIndex;
                }
            }
            if (rightChildIndex < length) {
                if (
                    (swapIndex === null && this.comparator(this.heap[rightChildIndex], this.heap[index]) < 0) ||
                    (swapIndex !== null && this.comparator(this.heap[rightChildIndex], this.heap[leftChildIndex]) < 0)
                ) {
                    swapIndex = rightChildIndex;
                }
            }
            if (swapIndex === null) break;
            [this.heap[index], this.heap[swapIndex]] = [this.heap[swapIndex], this.heap[index]];
            index = swapIndex;
        }
    }
}
