#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

struct Edge {
    int to;
    long long cost;
    Edge(int t, long long c) : to(t), cost(c) {}
};

struct State {
    int node;
    long long total_cost;
    long long min_edge;
    State(int n, long long tc, long long me) : node(n), total_cost(tc), min_edge(me) {}
    bool operator>(const State& other) const {
        return total_cost > other.total_cost;
    }
};

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        graph[u].emplace_back(v, cost);
    }

    priority_queue<State, vector<State>, greater<State>> pq;
    pq.emplace(0, 0, LLONG_MAX);
    long long max_score = -1;

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();
        int u = current.node;
        long long total_cost = current.total_cost;
        long long min_edge = current.min_edge;

        if (u == n - 1) {
            if (total_cost <= k) {
                if (min_edge != LLONG_MAX) {
                    max_score = max(max_score, min_edge);
                }
            }
            continue;
        }

        for (const Edge& edge : graph[u]) {
            int v = edge.to;
            long long cost = edge.cost;
            if (!online[v] && v != n - 1) {
                continue;
            }
            long long new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }
            long long new_min = min(min_edge, cost);
            pq.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}

