function solve(edges, online, k) {
    const n = online.length;
    const graph = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        graph[u].push({ to: v, cost });
    }

    const pq = new PriorityQueue((a, b) => a.total_cost - b.total_cost);
    pq.push({ node: 0, total_cost: 0, min_edge: Infinity });

    let max_score = -1;

    while (!pq.isEmpty()) {
        const { node, total_cost, min_edge } = pq.pop();

        if (node === n - 1) {
            if (total_cost <= k) {
                if (min_edge !== Infinity) {
                    max_score = Math.max(max_score, min_edge);
                }
            }
            continue;
        }

        for (const { to, cost } of graph[node]) {
            if (!online[to] && to !== n - 1) {
                continue;
            }
            const new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }
            const new_min = Math.min(min_edge, cost);
            pq.push({ node: to, total_cost: new_total, min_edge: new_min });
        }
    }

    return max_score;
}

class PriorityQueue {
    constructor(comparator = (a, b) => a - b) {
        this.heap = [];
        this.comparator = comparator;
    }

    push(value) {
        this.heap.push(value);
        this.heapifyUp();
    }

    pop() {
        if (this.heap.length === 0) return null;
        if (this.heap.length === 1) return this.heap.pop();
        const top = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown();
        return top;
    }

    heapifyUp() {
        let current = this.heap.length - 1;
        while (current > 0) {
            const parent = Math.floor((current - 1) / 2);
            if (this.comparator(this.heap[current], this.heap[parent]) >= 0) break;
            [this.heap[current], this.heap[parent]] = [this.heap[parent], this.heap[current]];
            current = parent;
        }
    }

    heapifyDown() {
        let current = 0;
        while (true) {
            const left = 2 * current + 1;
            const right = 2 * current + 2;
            let smallest = current;
            if (left < this.heap.length && this.comparator(this.heap[left], this.heap[smallest]) < 0) {
                smallest = left;
            }
            if (right < this.heap.length && this.comparator(this.heap[right], this.heap[smallest]) < 0) {
                smallest = right;
            }
            if (smallest === current) break;
            [this.heap[current], this.heap[smallest]] = [this.heap[smallest], this.heap[current]];
            current = smallest;
        }
    }

    isEmpty() {
        return this.heap.length === 0;
    }
}
