function solve(edges, online, k) {
    const n = online.length;
    const graph = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        graph[u].push({ to: v, cost });
    }

    const pq = new PriorityQueue((a, b) => a.total_cost - b.total_cost);
    pq.push({ node: 0, total_cost: 0, min_edge: Infinity });

    let max_score = -1;

    while (!pq.isEmpty()) {
        const { node, total_cost, min_edge } = pq.pop();

        if (node === n - 1) {
            if (total_cost <= k) {
                if (min_edge !== Infinity) {
                    max_score = Math.max(max_score, min_edge);
                }
            }
            continue;
        }

        for (const { to, cost } of graph[node]) {
            if (!online[to] && to !== n - 1) {
                continue;
            }
            const new_total = total_cost + cost;
            if (new_total > k) {
                continue;
            }
            const new_min = Math.min(min_edge, cost);
            pq.push({ node: to, total_cost: new_total, min_edge: new_min });
        }
    }

    return max_score;
}

class PriorityQueue {
    constructor(comparator = (a, b) => a - b) {
        this.heap = [];
        this.comparator = comparator;
    }

    push(value) {
        this.heap.push(value);
        this.heapifyUp();
    }

    pop() {
        if (this.heap.length === 0) return null;
        const top = this.heap[0];
        const bottom = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = bottom;
            this.heapifyDown();
        }
        return top;
    }

    heapifyUp() {
        let index = this.heap.length - 1;
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) break;
            [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
            index = parentIndex;
        }
    }

    heapifyDown() {
        let index = 0;
        const length = this.heap.length;
        while (true) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let smallestChildIndex = index;
            if (leftChildIndex < length && this.comparator(this.heap[leftChildIndex], this.heap[smallestChildIndex]) < 0) {
                smallestChildIndex = leftChildIndex;
            }
            if (rightChildIndex < length && this.comparator(this.heap[rightChildIndex], this.heap[smallestChildIndex]) < 0) {
                smallestChildIndex = rightChildIndex;
            }
            if (smallestChildIndex === index) break;
            [this.heap[index], this.heap[smallestChildIndex]] = [this.heap[smallestChildIndex], this.heap[index]];
            index = smallestChildIndex;
        }
    }

    isEmpty() {
        return this.heap.length === 0;
    }
}
